UPDATE "NOTIFICATIONPUBLISHER" SET "PUBLISHER_CLASS" = t.extension_name FROM ( VALUES ('ConsolePublisher', 'console') , ('CsWebexPublisher', 'webex') , ('JiraPublisher', 'jira') , ('MattermostPublisher', 'mattermost') , ('MsTeamsPublisher', 'msteams') , ('SendMailPublisher', 'email') , ('SlackPublisher', 'slack') , ('WebhookPublisher', 'webhook') ) AS t(publisher_class, extension_name) WHERE "PUBLISHER_CLASS" = t.publisher_class;
