ALTER TABLE "NOTIFICATIONRULE"
ALTER COLUMN "PUBLISHER_CONFIG"
TYPE JSONB USING "PUBLISHER_CONFIG"::JSONB;

UPDATE "NOTIFICATIONRULE" AS r SET "PUBLISHER_CONFIG" = NULL , "ENABLED" = FALSE FROM "NOTIFICATIONPUBLISHER" AS p WHERE p."ID" = r."PUBLISHER" AND p."EXTENSION_NAME" = 'console';
UPDATE "NOTIFICATIONRULE" AS r SET "PUBLISHER_CONFIG" = JSONB_BUILD_OBJECT( 'recipientAddresses', CASE WHEN NULLIF(r."PUBLISHER_CONFIG" ->> 'destination', '') IS NOT NULL THEN JSONB_BUILD_ARRAY(r."PUBLISHER_CONFIG" ->> 'destination') ELSE JSONB_BUILD_ARRAY() END ) , "ENABLED" = FALSE FROM "NOTIFICATIONPUBLISHER" AS p WHERE p."ID" = r."PUBLISHER" AND p."EXTENSION_NAME" = 'email';
UPDATE "NOTIFICATIONRULE" AS r SET "PUBLISHER_CONFIG" = JSONB_BUILD_OBJECT( 'projectKey', COALESCE("PUBLISHER_CONFIG" ->> 'destination', 'EXAMPLE') , 'issueType', COALESCE("PUBLISHER_CONFIG" ->> 'jiraTicketType', 'TASK') ) , "ENABLED" = FALSE FROM "NOTIFICATIONPUBLISHER" AS p WHERE p."ID" = r."PUBLISHER" AND p."EXTENSION_NAME" = 'jira';
UPDATE "NOTIFICATIONRULE" AS r SET "PUBLISHER_CONFIG" = JSONB_BUILD_OBJECT( 'destinationUrl', COALESCE("PUBLISHER_CONFIG" ->> 'destination', 'https://example.com') ) , "ENABLED" = FALSE FROM "NOTIFICATIONPUBLISHER" AS p WHERE p."ID" = r."PUBLISHER" AND p."EXTENSION_NAME" IN ('mattermost', 'msteams', 'slack', 'webex', 'webhook');

