CREATE TABLE "PROJECT_ACCESS_USERS" (
  "PROJECT_ID" BIGINT
, "USER_ID" BIGINT
, CONSTRAINT "PROJECT_ACCESS_USERS_PK" PRIMARY KEY ("PROJECT_ID", "USER_ID")
, CONSTRAINT "PROJECT_ACCESS_USERS_PROJECT_FK" FOREIGN KEY ("PROJECT_ID") REFERENCES "PROJECT" ("ID") ON DELETE CASCADE
, CONSTRAINT "PROJECT_ACCESS_USERS_USER_FK" FOREIGN KEY ("USER_ID") REFERENCES "USER" ("ID") ON DELETE CASCADE
);

CREATE INDEX "PROJECT_ACCESS_USERS_USER_IDX" ON "PROJECT_ACCESS_USERS" ("USER_ID");

CREATE OR REPLACE FUNCTION project_access_users_on_pat_update() RETURNS TRIGGER AS $$ BEGIN WITH rows_to_delete AS ( SELECT pau."PROJECT_ID" , pau."USER_ID" FROM "PROJECT_ACCESS_USERS" AS pau WHERE EXISTS ( SELECT 1 FROM old_table AS ot WHERE ot."PROJECT_ID" = pau."PROJECT_ID" ) AND NOT EXISTS ( SELECT 1 FROM "PROJECT_ACCESS_TEAMS" AS pat INNER JOIN "USERS_TEAMS" AS ut ON ut."TEAM_ID" = pat."TEAM_ID" WHERE pat."PROJECT_ID" = pau."PROJECT_ID" AND ut."USER_ID" = pau."USER_ID" ) ORDER BY pau."PROJECT_ID" , pau."USER_ID" FOR UPDATE ) DELETE FROM "PROJECT_ACCESS_USERS" AS pau USING rows_to_delete AS r WHERE pau."PROJECT_ID" = r."PROJECT_ID" AND pau."USER_ID" = r."USER_ID";
INSERT INTO "PROJECT_ACCESS_USERS" ("PROJECT_ID", "USER_ID") SELECT DISTINCT nt."PROJECT_ID" , ut."USER_ID" FROM new_table AS nt INNER JOIN "USERS_TEAMS" AS ut ON ut."TEAM_ID" = nt."TEAM_ID" ORDER BY nt."PROJECT_ID" , ut."USER_ID" ON CONFLICT DO NOTHING;
RETURN NULL; END; $$ LANGUAGE plpgsql;

CREATE OR REPLACE FUNCTION project_access_users_on_ut_update() RETURNS TRIGGER AS $$ BEGIN WITH rows_to_delete AS ( SELECT pau."PROJECT_ID" , pau."USER_ID" FROM "PROJECT_ACCESS_USERS" AS pau WHERE EXISTS ( SELECT 1 FROM old_table AS ot WHERE ot."USER_ID" = pau."USER_ID" ) AND NOT EXISTS ( SELECT 1 FROM "USERS_TEAMS" AS ut INNER JOIN "PROJECT_ACCESS_TEAMS" AS pat ON pat."TEAM_ID" = ut."TEAM_ID" WHERE ut."USER_ID" = pau."USER_ID" AND pat."PROJECT_ID" = pau."PROJECT_ID" ) ORDER BY pau."PROJECT_ID" , pau."USER_ID" FOR UPDATE ) DELETE FROM "PROJECT_ACCESS_USERS" AS pau USING rows_to_delete AS r WHERE pau."PROJECT_ID" = r."PROJECT_ID" AND pau."USER_ID" = r."USER_ID";
INSERT INTO "PROJECT_ACCESS_USERS" ("PROJECT_ID", "USER_ID") SELECT DISTINCT pat."PROJECT_ID" , nt."USER_ID" FROM new_table AS nt INNER JOIN "PROJECT_ACCESS_TEAMS" AS pat ON pat."TEAM_ID" = nt."TEAM_ID" ORDER BY pat."PROJECT_ID" , nt."USER_ID" ON CONFLICT DO NOTHING;
RETURN NULL; END; $$ LANGUAGE plpgsql;

CREATE TRIGGER trigger_project_access_users_on_pat_insert AFTER INSERT ON "PROJECT_ACCESS_TEAMS" REFERENCING NEW TABLE AS new_table FOR EACH STATEMENT EXECUTE FUNCTION project_access_users_on_pat_insert();
CREATE TRIGGER trigger_project_access_users_on_pat_delete AFTER DELETE ON "PROJECT_ACCESS_TEAMS" REFERENCING OLD TABLE AS old_table FOR EACH STATEMENT EXECUTE FUNCTION project_access_users_on_pat_delete();
CREATE TRIGGER trigger_project_access_users_on_pat_update AFTER UPDATE ON "PROJECT_ACCESS_TEAMS" REFERENCING OLD TABLE AS old_table NEW TABLE AS new_table FOR EACH STATEMENT EXECUTE FUNCTION project_access_users_on_pat_update();
CREATE TRIGGER trigger_project_access_users_on_ut_insert AFTER INSERT ON "USERS_TEAMS" REFERENCING NEW TABLE AS new_table FOR EACH STATEMENT EXECUTE FUNCTION project_access_users_on_ut_insert();
CREATE TRIGGER trigger_project_access_users_on_ut_delete AFTER DELETE ON "USERS_TEAMS" REFERENCING OLD TABLE AS old_table FOR EACH STATEMENT EXECUTE FUNCTION project_access_users_on_ut_delete();
CREATE TRIGGER trigger_project_access_users_on_ut_update AFTER UPDATE ON "USERS_TEAMS" REFERENCING OLD TABLE AS old_table NEW TABLE AS new_table FOR EACH STATEMENT EXECUTE FUNCTION project_access_users_on_ut_update();

CREATE OR REPLACE FUNCTION prevent_direct_project_access_users_writes()
RETURNS TRIGGER AS $$
BEGIN
  IF pg_trigger_depth() < 2 THEN
    RAISE EXCEPTION 'Direct modifications to PROJECT_ACCESS_USERS are not allowed.';
  END IF;
  RETURN NEW;
END;
$$ LANGUAGE plpgsql;

