UPDATE "VULNERABILITY_POLICY_BUNDLE"
   SET "UUID" = 'bc106cf4-3993-4e38-952d-d2f5f11412ed'
 WHERE "ID" = (SELECT MIN("ID") FROM "VULNERABILITY_POLICY_BUNDLE");

ALTER TABLE "VULNERABILITY_POLICY" ADD COLUMN "VULNERABILITY_POLICY_BUNDLE_ID" BIGINT;

UPDATE "VULNERABILITY_POLICY"
   SET "VULNERABILITY_POLICY_BUNDLE_ID" = (SELECT "ID" FROM "VULNERABILITY_POLICY_BUNDLE" LIMIT 1)
 WHERE EXISTS (SELECT 1 FROM "VULNERABILITY_POLICY_BUNDLE");

ALTER TABLE "VULNERABILITY_POLICY"
ADD CONSTRAINT "VULNERABILITY_POLICY_BUNDLE_FK"
FOREIGN KEY ("VULNERABILITY_POLICY_BUNDLE_ID")
REFERENCES "VULNERABILITY_POLICY_BUNDLE" ("ID");

CREATE INDEX "VULNERABILITY_POLICY_BUNDLE_ID_IDX"
    ON "VULNERABILITY_POLICY" ("VULNERABILITY_POLICY_BUNDLE_ID");

ALTER TABLE "VULNERABILITY_POLICY" ADD COLUMN "CONDITION" TEXT;

UPDATE "VULNERABILITY_POLICY"
   SET "CONDITION" = COALESCE("CONDITIONS"[1], 'false');

ALTER TABLE "VULNERABILITY_POLICY" ALTER COLUMN "CONDITION" SET NOT NULL;
ALTER TABLE "VULNERABILITY_POLICY" DROP COLUMN "CONDITIONS";

